import React, { useState, useEffect, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../api/axiosConfig';
import { Zap, TrendingUp, TrendingDown, ChevronLeft, ChevronRight, Activity, ShieldAlert, BarChart3, Box } from 'lucide-react';

const LiveMarketPage = () => {
    const { token } = useContext(AuthContext);
    const [history, setHistory] = useState([]);
    const [currentIndex, setCurrentIndex] = useState(0);
    const [stocks, setStocks] = useState([]);
    const [isConnected, setIsConnected] = useState(false);

    useEffect(() => {
        const fetchVault = async () => {
            try {
                const res = await api.get('/portfolio/history');
                setHistory(res.data);
                if (res.data.length > 0) initializeStocks(res.data[0].holdings);
            } catch (err) { console.error("VAULT_OFFLINE"); }
        };
        fetchVault();
    }, []);

    const initializeStocks = (holdingsData) => {
        try {
            let tickers = typeof holdingsData === 'string' ? JSON.parse(holdingsData) : holdingsData;
            if (typeof tickers === 'string') tickers = JSON.parse(tickers);
            setStocks(tickers.map(t => ({ ticker: t, price: Math.floor(Math.random() * 2000) + 500, change: 0.00 })));
        } catch (e) { setStocks([]); }
    };

    useEffect(() => {
        if (!token) return;
        const ws = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
        ws.onopen = () => setIsConnected(true);
        ws.onmessage = () => {
            setStocks(prev => prev.map(s => {
                const move = (Math.random() - 0.5) * 8;
                return { ...s, price: parseFloat((s.price + move).toFixed(2)), change: parseFloat(move.toFixed(2)) };
            }));
        };
        ws.onclose = () => setIsConnected(false);
        return () => ws.close();
    }, [token, currentIndex]);

    const navigate = (dir) => {
        let newIdx = currentIndex + dir;
        if (newIdx >= 0 && newIdx < history.length) {
            setCurrentIndex(newIdx);
            initializeStocks(history[newIdx].holdings);
        }
    };

    const activeNode = history[currentIndex];

    return (
        <div style={viewportWrapper}>
            {/* ── Fixed Top Section ── */}
            <div style={headerContainer}>
                <div style={navRow}>
                    <button onClick={() => navigate(1)} disabled={currentIndex === history.length - 1} style={navBtn}>
                        <ChevronLeft size={18}/> PREV
                    </button>
                    <div style={nodeTitleBox}>
                        <Box size={14} color="var(--accent-primary)" />
                        <span style={nodeText}>{activeNode ? activeNode.goal : 'INITIALIZING...'}</span>
                        <span style={nodeCounter}>{currentIndex + 1} / {history.length}</span>
                    </div>
                    <button onClick={() => navigate(-1)} disabled={currentIndex === 0} style={navBtn}>
                        NEXT <ChevronRight size={18}/>
                    </button>
                </div>

                <div style={analyticsRow}>
                    <div style={statCard}>
                        <BarChart3 size={14} color="var(--accent-primary)" />
                        <div style={progressBar}><div style={progressFill(activeNode?.risk_score || 50)} /></div>
                        <span style={statLabel}>RISK: {activeNode?.risk_score}%</span>
                    </div>
                    <div style={statCard}>
                        <ShieldAlert size={14} color="#ef4444" />
                        <span style={statLabel}>RESILIENCE: HIGH</span>
                    </div>
                    <div style={connectionStatus(isConnected)}>
                        <Activity size={12} /> {isConnected ? 'LIVE_UPLINK' : 'LINK_LOST'}
                    </div>
                </div>
            </div>

            {/* ── Scrollable Ticker Area ── */}
            <div style={scrollArea}>
                <div style={tickerGrid}>
                    {stocks.map((stock, i) => (
                        <div key={i} style={stockCard(stock.change >= 0)}>
                            <div style={cardHeader}>
                                <span style={tickerName}>{stock.ticker}</span>
                                <Zap size={14} color={stock.change >= 0 ? "#10b981" : "#ef4444"} />
                            </div>
                            <div style={priceText}>₹{stock.price.toLocaleString()}</div>
                            <div style={changeText(stock.change >= 0)}>
                                {stock.change >= 0 ? <TrendingUp size={14}/> : <TrendingDown size={14}/>}
                                {stock.change >= 0 ? '+' : ''}{stock.change}%
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
};

/* --- Visual Styles --- */
const viewportWrapper = { 
    height: 'calc(100vh - 70px)', // Account for Navbar height
    display: 'flex', 
    flexDirection: 'column', 
    background: '#07080a', 
    overflow: 'hidden' 
};

const headerContainer = { 
    padding: '1.5rem 2rem', 
    background: '#0a0b0e', 
    borderBottom: '1px solid #1a1d23' 
};

const navRow = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' };
const navBtn = { background: 'none', border: 'none', color: 'var(--accent-primary)', cursor: 'pointer', fontSize: '0.7rem', fontWeight: 800, fontFamily: 'monospace', display: 'flex', alignItems: 'center', gap: '5px' };
const nodeTitleBox = { display: 'flex', alignItems: 'center', gap: '15px', background: '#111318', padding: '8px 16px', borderRadius: '8px', border: '1px solid #1a1d23' };
const nodeText = { fontSize: '0.8rem', fontWeight: 700, color: '#fff' };
const nodeCounter = { fontSize: '0.6rem', color: 'var(--accent-primary)', background: 'rgba(16,185,129,0.1)', padding: '2px 6px', borderRadius: '4px' };

const analyticsRow = { display: 'flex', gap: '2rem', alignItems: 'center' };
const statCard = { display: 'flex', alignItems: 'center', gap: '10px', background: '#111318', padding: '6px 12px', borderRadius: '6px', border: '1px solid #1a1d23' };
const statLabel = { fontSize: '0.65rem', fontWeight: 800, color: '#888' };
const progressBar = { width: '60px', height: '4px', background: '#222', borderRadius: '2px' };
const progressFill = (val) => ({ width: `${val}%`, height: '100%', background: 'var(--accent-primary)', borderRadius: '2px' });
const connectionStatus = (online) => ({ marginLeft: 'auto', display: 'flex', alignItems: 'center', gap: '8px', fontSize: '0.6rem', fontWeight: 900, color: online ? '#10b981' : '#ef4444' });

const scrollArea = { flex: 1, padding: '2rem', overflowY: 'auto' };
const tickerGrid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '1.5rem' };
const stockCard = (up) => ({ padding: '1.5rem', background: '#111318', border: '1px solid #1a1d23', borderRadius: '16px', borderLeft: `4px solid ${up ? '#10b981' : '#ef4444'}` });
const cardHeader = { display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' };
const tickerName = { fontSize: '0.8rem', fontWeight: 900, color: 'var(--accent-primary)', fontFamily: 'monospace' };
const priceText = { fontSize: '1.8rem', fontWeight: 900, color: '#fff', fontFamily: 'monospace' };
const changeText = (up) => ({ color: up ? '#10b981' : '#ef4444', fontSize: '0.8rem', fontWeight: 800, display: 'flex', alignItems: 'center', gap: '6px', marginTop: '8px' });

export default LiveMarketPage;
